import{_ as t,o as a,c as o,a3 as i}from"./chunks/framework.BRHnm6VC.js";const u=JSON.parse('{"title":"How to Practice & Study Code","description":"","frontmatter":{"title":"How to Practice & Study Code","nav_order":5,"has_children":true},"headers":[],"relativePath":"practice/index.md","filePath":"practice/index.md"}'),s={name:"practice/index.md"};function n(r,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="how-to-practice-study-code" tabindex="-1">How to Practice &amp; Study Code <a class="header-anchor" href="#how-to-practice-study-code" aria-label="Permalink to &quot;How to Practice &amp; Study Code&quot;">​</a></h1><p>Preparing for Paper 1 is different from studying for Paper 2. You can&#39;t just read notes — you need to <strong>think like a programmer</strong>. This section shows you how to do that, whether or not you have Delphi at home.</p><h2 id="choose-your-path" tabindex="-1">Choose your path <a class="header-anchor" href="#choose-your-path" aria-label="Permalink to &quot;Choose your path&quot;">​</a></h2><table tabindex="0"><thead><tr><th>My situation</th><th>Where to start</th></tr></thead><tbody><tr><td>I don&#39;t have a Windows PC at home</td><td><a href="./study-without-delphi.html">Studying Without Delphi →</a></td></tr><tr><td>I have Windows and can install software</td><td><a href="./setup-delphi.html">Setting Up &amp; Practising in Delphi →</a></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Both paths matter</p><p>Even if you have Delphi at home, <strong>start with the &quot;Studying Without Delphi&quot; guide</strong>. The thinking and tracing skills there are what Paper 1 actually tests — Delphi is just where you type the answers.</p></div><hr><h2 id="what-the-exam-really-tests" tabindex="-1">What the exam really tests <a class="header-anchor" href="#what-the-exam-really-tests" aria-label="Permalink to &quot;What the exam really tests&quot;">​</a></h2><p>Paper 1 is not testing whether you can drag a button onto a form. It tests whether you can <strong>read a problem, think through a solution, and write correct code</strong>.</p><p>The Delphi form is just a container. Everything that matters happens <strong>inside the event handler</strong>:</p><div class="language-pascal vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">pascal</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">procedure</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> TForm1.btnCalculateClick</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Sender: TObject);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">begin</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ← This is what the exam tests.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  //    This logic works the same in any Pascal program.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  //    You can study it without ever opening Delphi.</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>The implication: you can study the vast majority of Paper 1 content with <strong>nothing more than a pen and paper</strong>.</p><hr><h2 id="core-skills-—-what-s-inside-the-container" tabindex="-1">Core skills — what&#39;s &quot;inside the container&quot; <a class="header-anchor" href="#core-skills-—-what-s-inside-the-container" aria-label="Permalink to &quot;Core skills — what&#39;s &quot;inside the container&quot;&quot;">​</a></h2><p>These are the skills Paper 1 tests. They are the same whether you study them on paper, in an online compiler, or in Delphi.</p><h3 id="grade-10-foundations" tabindex="-1">Grade 10 foundations <a class="header-anchor" href="#grade-10-foundations" aria-label="Permalink to &quot;Grade 10 foundations&quot;">​</a></h3><ul><li>[ ] Declaring variables with the correct data type (<code>Integer</code>, <code>Real</code>, <code>String</code>, <code>Boolean</code>, <code>Char</code>)</li><li>[ ] Assignments and arithmetic operators (<code>+</code>, <code>-</code>, <code>*</code>, <code>/</code>, <code>div</code>, <code>mod</code>)</li><li>[ ] <code>if / else if / else</code> selection</li><li>[ ] <code>case</code> statements</li><li>[ ] <code>for</code> loops (counting up and down)</li><li>[ ] <code>while</code> and <code>repeat...until</code> loops</li><li>[ ] Reading from and writing to components (<code>edtInput.Text</code>, <code>lblOutput.Caption</code>)</li></ul><h3 id="grade-11-skills" tabindex="-1">Grade 11 skills <a class="header-anchor" href="#grade-11-skills" aria-label="Permalink to &quot;Grade 11 skills&quot;">​</a></h3><ul><li>[ ] 1D arrays — declaring, filling, searching, sorting</li><li>[ ] 2D arrays — rows and columns, nested loops</li><li>[ ] String functions: <code>Length</code>, <code>Copy</code>, <code>Pos</code>, <code>UpCase</code>, <code>LowerCase</code>, <code>Trim</code>, <code>IntToStr</code>, <code>StrToInt</code></li><li>[ ] Math functions: <code>Round</code>, <code>Trunc</code>, <code>Abs</code>, <code>Sqr</code>, <code>Sqrt</code></li><li>[ ] Input validation (while loops checking conditions)</li><li>[ ] SQL <code>SELECT</code> with <code>WHERE</code>, <code>ORDER BY</code>, <code>GROUP BY</code>, <code>HAVING</code></li></ul><h3 id="grade-12-skills" tabindex="-1">Grade 12 skills <a class="header-anchor" href="#grade-12-skills" aria-label="Permalink to &quot;Grade 12 skills&quot;">​</a></h3><ul><li>[ ] Procedures with parameters (<code>var</code> and value parameters)</li><li>[ ] Functions with return values (<code>Result :=</code>)</li><li>[ ] Text file operations (<code>AssignFile</code>, <code>Reset</code>, <code>Rewrite</code>, <code>ReadLn</code>, <code>WriteLn</code>, <code>CloseFile</code>)</li><li>[ ] OOP: classes, constructors, properties, methods</li><li>[ ] Inheritance and method overriding</li><li>[ ] SQL <code>INSERT</code>, <code>UPDATE</code>, <code>DELETE</code></li><li>[ ] Connecting Delphi to a database (<code>TADOConnection</code>, <code>TADOQuery</code>)</li></ul><hr><h2 id="how-to-use-this-section" tabindex="-1">How to use this section <a class="header-anchor" href="#how-to-use-this-section" aria-label="Permalink to &quot;How to use this section&quot;">​</a></h2><ol><li>Work through <a href="./study-without-delphi.html">Studying Without Delphi</a> to build logic, tracing, and reading skills</li><li>If you have Windows, follow <a href="./setup-delphi.html">Setting Up Delphi</a> to practice in the real environment</li><li>Use <a href="./../quick-study/">Quick Study</a> cheat sheets as a reference while practising</li><li>Practice past papers under timed conditions — one question per 45 minutes</li></ol>`,23)])])}const m=t(s,[["render",n]]);export{u as __pageData,m as default};
